mapper.insert:
insert into ly_tour_income(
    tour_id, income_type, amount, received_time, remark, create_time
) values (
    #{tourId}, #{incomeType}, #{amount}, #{receivedTime}, #{remark}, sysdate()
)

insert into ly_tour_cost(
    tour_id, category, amount, payment_method, advance_user_name, status, receipt_url, occur_date, remark, create_time
) values (
    #{tourId}, #{category}, #{amount}, #{paymentMethod}, #{advanceUserName}, #{status}, #{receiptUrl}, #{occurDate}, #{remark}, sysdate()
)

mapper.select:
select ifnull(sum(amount), 0)
from ly_tour_income
where tour_id = #{tourId}
